content.query:
Tailscale_Configuration_CL
| where TimeGenerated {TimeRange}
| summarize TotalEvents = count(), UniqueActors = dcount(tostring(Actor.loginName)), ACLChanges = countif(Action == "WRITE" and tostring(Target.type) == "ACL"), AuthKeysCreated = countif(Action == "CREATE" and tostring(Target.type) == "AUTH_KEY")
